128	// removePersonasSection removes the personas section from the content
129	func (c *ClaudeInjectorImpl) removePersonasSection(content string) string {
130		// Find personas section and remove it
131		startMarker := PersonasStartMarker
132		endMarker := PersonasEndMarker
133	
134		// Handle both proper sections and malformed ones
135		startIdx := strings.Index(content, startMarker)
136		if startIdx == -1 {
137			return content // No personas section found
138		}
139	
140		endIdx := strings.Index(content[startIdx:], endMarker)
141		if endIdx == -1 {
142			// Malformed section - remove from start marker to end of file
143			return strings.TrimSpace(content[:startIdx])
144		}
145	
146		// Calculate absolute end index
147		endIdx = startIdx + endIdx + len(endMarker)
148	
149		// Remove the section
150		before := content[:startIdx]
151		after := content[endIdx:]
152	
153		// Clean up whitespace
154		before = strings.TrimRight(before, " \t\n")
155		after = strings.TrimLeft(after, " \t\n")
156	
157		if before != "" && after != "" {
158			return before + "\n\n" + after
159		} else if before != "" {
160			return before
161		} else if after != "" {
162			return after
163		} else {
164			return ""
165		}
166	}
