198	// extractRolePersonaPairs extracts role->persona mappings from the content
199	func (c *ClaudeInjectorImpl) extractRolePersonaPairs(content string) map[string]string {
200		pairs := make(map[string]string)
201	
202		// Find personas section
203		startIdx := strings.Index(content, PersonasStartMarker)
204		if startIdx == -1 {
205			return pairs
206		}
207	
208		endIdx := strings.Index(content[startIdx:], PersonasEndMarker)
209		if endIdx == -1 {
210			return pairs
211		}
212	
213		// Extract personas section
214		endIdx = startIdx + endIdx
215		personasSection := content[startIdx:endIdx]
216	
217		// Parse role and persona names using regex
218		// Format: "### Role: persona-name" - must be at start of line
219		personaPattern := regexp.MustCompile(`(?m)^###\s+([^:]+):\s+([^\n]+)`)
220		matches := personaPattern.FindAllStringSubmatch(personasSection, -1)
221	
222		for _, match := range matches {
223			if len(match) > 2 {
224				role := strings.TrimSpace(match[1])
225				personaName := strings.TrimSpace(match[2])
226				if role != "" && personaName != "" {
227					pairs[role] = personaName
228				}
229			}
230		}
231	
232		return pairs
233	}
