235	// formatRoleDisplay formats a role name for display (e.g., "code-reviewer" -> "Code Reviewer")
236	func formatRoleDisplay(role string) string {
237		if role == "" {
238			return ""
239		}
240	
241		// Replace separators with spaces and title case each word
242		words := regexp.MustCompile(`[-_]+`).Split(role, -1)
243		var formattedWords []string
244	
245		for _, word := range words {
246			if word != "" {
247				// Title case: first letter uppercase, rest lowercase
248				if len(word) == 1 {
249					formattedWords = append(formattedWords, strings.ToUpper(word))
250				} else {
251					formatted := strings.ToUpper(word[:1]) + strings.ToLower(word[1:])
252					formattedWords = append(formattedWords, formatted)
253				}
254			}
255		}
256	
257		return strings.Join(formattedWords, " ")
258	}
