369	// formatRoleFromDisplay converts display format back to role format
370	func formatRoleFromDisplay(display string) string {
371		// Convert "Code Reviewer" back to "code-reviewer"
372		words := strings.Fields(display)
373		var roleWords []string
374	
375		for _, word := range words {
376			roleWords = append(roleWords, strings.ToLower(word))
377		}
378	
379		return strings.Join(roleWords, "-")
380	}

