202	// loadConfig loads the persona configuration from the config file
203	func (b *BindingManagerImpl) loadConfig() (*PersonaConfig, error) {
204		if !fileExists(b.configPath) {
205			return nil, os.ErrNotExist
206		}
207	
208		content, err := os.ReadFile(b.configPath)
209		if err != nil {
210			return nil, NewPersonaError(ErrorFileOperation,
211				fmt.Sprintf("failed to read config file %s", b.configPath), err)
212		}
213	
214		// Parse as generic map first to handle the full config structure
215		var fullConfig map[string]interface{}
216		if err := yaml.Unmarshal(content, &fullConfig); err != nil {
217			return nil, NewPersonaError(ErrorInvalidConfig,
218				fmt.Sprintf("failed to parse config file %s", b.configPath), err)
219		}
