126	// ListPersonas returns all available personas. Project personas override
127	// library personas of the same name; both sets are listed, with the project
128	// persona taking precedence when names collide.
129	func (l *PersonaLoaderImpl) ListPersonas() ([]*Persona, error) {
130		// Project personas first so they win on collision.
131		byName := map[string]*Persona{}
132		var ordered []string
133	
134		for _, dir := range []struct {
135			path   string
136			source string
137		}{
138			{l.projectDir, SourceProject},
139			{l.personasDir, SourceLibrary},
140		} {
141			if dir.path == "" || !dirExists(dir.path) {
142				continue
143			}
144			entries, err := os.ReadDir(dir.path)
145			if err != nil {
146				return nil, NewPersonaError(ErrorFileOperation,
147					fmt.Sprintf("failed to read personas directory %s", dir.path), err)
148			}
149			for _, entry := range entries {
150				if entry.IsDir() {
151					continue
152				}
153				if !strings.HasSuffix(entry.Name(), PersonaFileExtension) {
154					continue
155				}
156				if entry.Name() == "README.md" || entry.Name() == "readme.md" {
157					continue
158				}
159				personaName := strings.TrimSuffix(entry.Name(), PersonaFileExtension)
160				if _, seen := byName[personaName]; seen {
161					continue
162				}
163				persona, err := readPersonaFile(filepath.Join(dir.path, entry.Name()), dir.source)
164				if err != nil {
165					_, _ = fmt.Fprintf(os.Stderr, "Warning: Skipping invalid persona %s: %v\n", entry.Name(), err)
166					continue
167				}
168				byName[personaName] = persona
169				ordered = append(ordered, personaName)
170			}
171		}
172	
173		result := make([]*Persona, 0, len(byName))
174		for _, name := range ordered {
175			result = append(result, byName[name])
176		}
177		return result, nil
178	}
